prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  ?taskName
  (COUNT(DISTINCT ?msg) AS ?messageCount)
  (GROUP_CONCAT(DISTINCT ?msgName; SEPARATOR=" | ") AS ?messages)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  # Find message flows attached to the task, and collect their referenced message
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?taskRefOrId .

  FILTER(STRENDS(STR(?task), ?taskRefOrId))

  OPTIONAL {
    ?mf bboExt:messageRef ?msgId .
    FILTER(STRLEN(STR(?msgId)) > 0)
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:id ?msgId .
    ?msg bbo:name ?msgName .
  }

  # Also allow message flows where task is target
  UNION
  {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo ;
        bboExt:targetRef ?taskRefOrId .
    FILTER(STRENDS(STR(?task), ?taskRefOrId))

    OPTIONAL {
      ?mf bboExt:messageRef ?msgId .
      FILTER(STRLEN(STR(?msgId)) > 0)
      ?msg a bboExt:Message ;
           tai:belongsTo ?choreo ;
           bbo:id ?msgId .
      ?msg bbo:name ?msgName .
    }
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
OPTIONAL { ?task bbo:name ?taskName . }
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?task
  ?taskName
  (COUNT(DISTINCT ?msg) AS ?messageCount)
  (GROUP_CONCAT(DISTINCT ?msgName; SEPARATOR=" | ") AS ?messages)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # Message flows adjacent to the task (either source or target)
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      (bboExt:sourceRef ?taskRefString || bboExt:targetRef ?taskRefString) .

  # Join message flow string refs to the task's URI suffix
  FILTER(
    STRENDS(STR(?task), ?taskRefString)
  )

  OPTIONAL {
    ?mf bboExt:messageRef ?msgId .
    FILTER(BOUND(?msgId) && STRLEN(STR(?msgId)) > 0)
    ?msg a bboExt:Message ;
         tai:belongsTo ?choreo ;
         bbo:id ?msgId ;
         bbo:name ?msgName .
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

