SELECT DISTINCT
  ?kind
  ?idValue
WHERE {
  {
    SELECT DISTINCT ?kind ?idValue WHERE {
      BIND("taskId" AS ?kind)
      ?model a bboExt:Model ; tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?def .
      ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo ; bbo:id ?idValue .
    }
    LIMIT 200
  }
  UNION
  {
    SELECT DISTINCT ?kind ?idValue WHERE {
      BIND("msgFlowSrc" AS ?kind)
      ?model a bboExt:Model ; tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?def .
      ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo ; bboExt:sourceRef ?idValue .
    }
    LIMIT 200
  }
  UNION
  {
    SELECT DISTINCT ?kind ?idValue WHERE {
      BIND("msgFlowTgt" AS ?kind)
      ?model a bboExt:Model ; tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?def .
      ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo ; bboExt:targetRef ?idValue .
    }
    LIMIT 200
  }
}
LIMIT 60

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  (COUNT(DISTINCT ?msg) AS ?messageCount)
  (GROUP_CONCAT(DISTINCT ?msgName; SEPARATOR=" | ") AS ?messages)
WHERE {
  ?model a bboExt:Model ; tai:originalId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?def .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bboExt:initiatingParticipantRef ?taskPartRef .
  OPTIONAL { ?task bbo:name ?taskName . }

  {
    ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo ;
        bboExt:sourceRef ?taskPartRef ;
        bboExt:messageRef ?msgId .
    ?msg a bboExt:Message ; tai:belongsTo ?choreo ;
         bbo:id ?msgId ; bbo:name ?msgName .
  }
  UNION
  {
    ?mf a bboExt:MessageFlow ; tai:belongsTo ?choreo ;
        bboExt:targetRef ?taskPartRef ;
        bboExt:messageRef ?msgId .
    ?msg a bboExt:Message ; tai:belongsTo ?choreo ;
         bbo:id ?msgId ; bbo:name ?msgName .
  }
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

